#include <stdio.h>
#include <stdbool.h>
#include <stdlib.h>
#include <string.h>

bool evaluateBooleanExpression(char* expression) {
    int len = strlen(expression);
    bool* stack = (bool*)malloc(len * sizeof(bool));
    int top = -1;
    for (int i = 0; i < len; i++) {
        if (expression[i] == ',') continue;
        if (expression[i] == 't') {
            stack[++top] = true;
        } else if (expression[i] == 'f') {
            stack[++top] = false;
        } else if (expression[i] == '!') {
            bool temp = stack[top];
            stack[top] = !temp;
        } else if (expression[i] == '&') {
            bool temp1 = stack[top--];
            bool temp2 = stack[top];
            stack[top] = temp1 && temp2;
        } else if (expression[i] == '|') {
            bool temp1 = stack[top--];
            bool temp2 = stack[top];
            stack[top] = temp1 || temp2;
        }
    }
    bool result = stack[top];
    free(stack);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char expression[20005];
        scanf("%s", expression);
        bool result = evaluateBooleanExpression(expression);
        printf("%s\n", result ? "true" : "false");
    }
    return 0;
}

