#include <iostream>
#include <stack>
#include <string>

bool evaluateBooleanExpression(const std::string& expression) {
    std::stack<bool> stack;
    for (char c : expression) {
        if (c == ',') continue;
        if (c == 't') {
            stack.push(true);
        } else if (c == 'f') {
            stack.push(false);
        } else if (c == '!') {
            bool temp = stack.top();
            stack.pop();
            stack.push(!temp);
        } else if (c == '&') {
            bool temp1 = stack.top();
            stack.pop();
            bool temp2 = stack.top();
            stack.pop();
            stack.push(temp1 && temp2);
        } else if (c == '|') {
            bool temp1 = stack.top();
            stack.pop();
            bool temp2 = stack.top();
            stack.pop();
            stack.push(temp1 || temp2);
        }
    }
    return stack.top();
}

int main() {
    int T;
    std::cin >> T;
    while (T--) {
        std::string expression;
        std::cin >> expression;
        bool result = evaluateBooleanExpression(expression);
        std::cout << (result ? "true" : "false") << std::endl;
    }
    return 0;
}

code.Java:
import java.util.Stack;
import java.util.Scanner;

public class Main {
    public static boolean evaluateBooleanExpression(String expression) {
        Stack<Boolean> stack = new Stack<>();
        for (char c : expression.toCharArray()) {
            if (c == ',') continue;
            if (c == 't') {
                stack.push(true);
            } else if (c == 'f') {
                stack.push(false);
            } else if (c == '!') {
                boolean temp = stack.pop();
                stack.push(!temp);
            } else if (c == '&') {
                boolean temp1 = stack.pop();
                boolean temp2 = stack.pop();
                stack.push(temp1 && temp2);
            } else if (c == '|') {
                boolean temp1 = stack.pop();
                boolean temp2 = stack.pop();
                stack.push(temp1 || temp2);
            }
        }
        return stack.pop();
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        scanner.nextLine();
        while (T-- > 0) {
            String expression = scanner.nextLine();
            boolean result = evaluateBooleanExpression(expression);
            System.out.println(result ? "true" : "false");
        }
    }
}

