def evaluateBooleanExpression(expression):
    stack = []
    for c in expression:
        if c == ',':
            continue
        if c == 't':
            stack.append(True)
        elif c == 'f':
            stack.append(False)
        elif c == '!':
            temp = stack.pop()
            stack.append(not temp)
        elif c == '&':
            temp1 = stack.pop()
            temp2 = stack.pop()
            stack.append(temp1 and temp2)
        elif c == '|':
            temp1 = stack.pop()
            temp2 = stack.pop()
            stack.append(temp1 or temp2)
    return stack[0]

t = int(input())
for _ in range(t):
    expression = input()
    result = evaluateBooleanExpression(expression)
    print(result)

